import{_ as o,o as t,c as r,a5 as c}from"./chunks/framework.C1VOsJ6A.js";const u=JSON.parse('{"title":"Account operator","description":"","frontmatter":{},"headers":[],"relativePath":"reference/components/account-operator.md","filePath":"reference/components/account-operator.md"}'),a={name:"reference/components/account-operator.md"};function n(i,e,s,d,l,h){return t(),r("div",null,[...e[0]||(e[0]=[c('<h1 id="account-operator" tabindex="-1">Account operator <a class="header-anchor" href="#account-operator" aria-label="Permalink to &quot;Account operator&quot;">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>The account operator is the Platform Mesh component that converts defined account or organization entities into live control-plane structure. It owns reconciliation of the <code>Account</code>-Resource and ties its lifecycle to <strong>kcp</strong> workspace lifecycle. It ensures that each account gets the right isolation, workspace typing, and discoverable metadata.</p><p>Its role is to sit between the tenancy declared and how KCP exposes that tenancy without concerning itself with the implementation of identity or access management.</p><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><h3 id="account-core-platform-mesh-io-v1alpha1" tabindex="-1"><strong>Account (<code>core.platform-mesh.io/v1alpha1</code>)</strong> <a class="header-anchor" href="#account-core-platform-mesh-io-v1alpha1" aria-label="Permalink to &quot;**Account (`core.platform-mesh.io/v1alpha1`)**&quot;">​</a></h3><p><code>Account</code> represents an entity in the workspace tree that can potentially hold other Accounts. <code>spec.type</code> currently only distinguishes an <strong>organization</strong> (type: <code>org</code>) from an <strong>account</strong> (type: <code>account</code>) but will possibly support other account types in the future. The spec carries display metadata, optional extensions, and structured <code>data</code>.</p><p>Reconciliation of an <code>Account</code> resource runs through the following steps:</p><ol><li>Webhooks validate the <code>Account</code> and set <code>spec.creator</code> to the respective Kubernetes user creating the resource.</li><li>Depending on the account type, one or more finalizers are added for later cleanup.</li><li>For accounts of type <code>org</code>, <code>WorkspaceTypes</code> for the organization&#39;s <code>Workspace</code> itself and its child <code>Accounts</code> are created.</li><li>A <code>Workspace</code> for the <code>Account</code> is created, using one of the above mentioned <code>WorkspaceTypes</code>, depending on the account type.</li><li>An <code>AccountInfo</code> resource of name <code>account</code> is created within the <code>Account</code>&#39;s <code>Workspace</code> and populated with information.</li><li>Readiness of the resource itself is blocked until the earlier created <code>Workspace</code> is ready, i.e. potential initalizers have finished. This ensures that the <a href="/pr-preview/pr-125/reference/components/security-operator.html">security operator</a> is finished with its work.</li></ol><h3 id="accountinfo-core-platform-mesh-io-v1alpha1" tabindex="-1"><strong>AccountInfo (<code>core.platform-mesh.io/v1alpha1</code>)</strong> <a class="header-anchor" href="#accountinfo-core-platform-mesh-io-v1alpha1" aria-label="Permalink to &quot;**AccountInfo (`core.platform-mesh.io/v1alpha1`)**&quot;">​</a></h3><p>An <code>AccountInfo</code> resource with name <code>account</code> is created by the account operator in an account&#39;s workspace and holds information about the account the workspace belongs to. Its purpose is to expose that information to internal components that don&#39;t have information about or permission to workspaces/accounts higher up in the tree. It is comparable to the <code>LogicalCluster</code> object named <code>cluster</code> in every KCP workspace.</p><p>Reconciliation of an <code>AccountInfo</code> resource runs through the following steps:</p><ol><li>A finalizer is added. There are no other actions happening until the resource is deleted. Other components like the <a href="/pr-preview/pr-125/reference/components/security-operator.html">security operator</a> are expected to add their own finalizers when depending on information of the resource for e.g. <code>Workspace</code> termination.</li><li>During deletion, removal of the resource is blocked by withholding finalizer removal until the <code>Workspace</code>/<code>Account</code> does not have any child accounts anymore.</li></ol><p>Together, these pieces implement the account model described in <a href="/pr-preview/pr-125/concepts/account-model.html">Account model</a> and the resource-oriented view in <a href="/pr-preview/pr-125/reference/resources/account-resource.html">Account resource</a>.</p><h2 id="links" tabindex="-1">Links <a class="header-anchor" href="#links" aria-label="Permalink to &quot;Links&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Kind</th><th>Link</th></tr></thead><tbody><tr><td>Source repository</td><td><a href="https://github.com/platform-mesh/account-operator" target="_blank" rel="noreferrer">platform-mesh/account-operator</a></td></tr><tr><td>Helm charts</td><td><a href="https://github.com/platform-mesh/helm-charts" target="_blank" rel="noreferrer">platform-mesh/helm-charts</a> — <code>charts/account-operator</code>, <code>charts/account-operator-crds</code></td></tr></tbody></table><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/pr-preview/pr-125/concepts/account-model.html">Account model</a></li><li><a href="/pr-preview/pr-125/reference/resources/account-resource.html">Account resource</a></li><li><a href="./kcp.html">kcp</a></li></ul>',18)])])}const m=o(a,[["render",n]]);export{u as __pageData,m as default};
